import React from "react";
import "./Result.css";

const INDUSTRY_META = {
    "Công nghệ thông tin": { icon: "💻", color: "#6366f1", bg: "rgba(99,102,241,0.12)" },
    "Quản trị kinh doanh": { icon: "📊", color: "#f59e0b", bg: "rgba(245,158,11,0.12)" },
    "Marketing": { icon: "📣", color: "#ec4899", bg: "rgba(236,72,153,0.12)" },
    "Tài chính - Kế toán": { icon: "💰", color: "#10b981", bg: "rgba(16,185,129,0.12)" },
    "Nhân sự": { icon: "👥", color: "#3b82f6", bg: "rgba(59,130,246,0.12)" },
    "Thiết kế": { icon: "🎨", color: "#a855f7", bg: "rgba(168,85,247,0.12)" },
    "Logistics": { icon: "🚚", color: "#f97316", bg: "rgba(249,115,22,0.12)" },
    "Giáo dục": { icon: "🎓", color: "#14b8a6", bg: "rgba(20,184,166,0.12)" },
};

const getMeta = (industry) =>
    INDUSTRY_META[industry] || { icon: "📁", color: "#6366f1", bg: "rgba(99,102,241,0.12)" };

/* ─── Mini bar cho top industries ─── */
const IndustryBar = ({ label, value, isTop, topColor }) => {
    const meta = getMeta(label);
    return (
        <div className={`ind-row ${isTop ? "is-top" : ""}`}>
            <span className="ind-icon">{meta.icon}</span>
            <span className="ind-name">{label}</span>
            <div className="ind-track">
                <div
                    className="ind-fill"
                    style={{
                        width: `${(value * 100).toFixed(1)}%`,
                        background: isTop ? topColor : "rgba(255,255,255,0.15)",
                    }}
                />
            </div>
            <span className="ind-pct">{(value * 100).toFixed(0)}%</span>
        </div>
    );
};

/* ─── Main Component ─── */
const Result = ({ data }) => {
    if (!data) return null;

    const { predicted_industry, confidence, probabilities } = data;
    const meta = getMeta(predicted_industry);
    const pct = (confidence * 100).toFixed(1);
    const sorted = Object.entries(probabilities).sort((a, b) => b[1] - a[1]);

    const level =
        confidence >= 0.7 ? { label: "Rất cao", cls: "lv-high" } :
            confidence >= 0.45 ? { label: "Khá cao", cls: "lv-med" } :
                { label: "Thấp", cls: "lv-low" };

    return (
        <div className="result-wrap" style={{ "--accent": meta.color, "--accent-bg": meta.bg }}>

            {/* ── HEADLINE ── */}
            <div className="result-headline">
                <span className="hl-tag">Kết quả phân tích CV</span>
                <div className="hl-label">CV này thuộc nhóm ngành</div>
                <div className="hl-industry">
                    <span className="hl-icon">{meta.icon}</span>
                    <span className="hl-name">{predicted_industry}</span>
                </div>
            </div>

            {/* ── CONFIDENCE ── */}
            <div className="conf-block">
                <div className="conf-row">
                    <span className="conf-title">Độ phù hợp</span>
                    <span className={`conf-badge ${level.cls}`}>{level.label}</span>
                </div>
                <div className="conf-track">
                    <div
                        className="conf-fill"
                        style={{ width: `${pct}%`, background: meta.color }}
                    />
                </div>
                <div className="conf-nums">
                    <span className="conf-pct" style={{ color: meta.color }}>{pct}%</span>
                    <span className="conf-hint">độ tin cậy của mô hình</span>
                </div>
            </div>

            {/* ── DIVIDER ── */}
            <div className="divider" />

            {/* ── TOP INDUSTRIES ── */}
            <div className="ranks-block">
                <div className="ranks-title">Xác suất theo ngành nghề</div>
                <div className="ranks-list">
                    {sorted.map(([label, val], i) => (
                        <IndustryBar
                            key={label}
                            label={label}
                            value={val}
                            isTop={i === 0}
                            topColor={meta.color}
                        />
                    ))}
                </div>
            </div>

        </div>
    );
};

export default Result;
